type userRepo struct {
    db *gorm.DB
}
func (r *userRepo) GetByID(ctx context.Context, id int64) (*User, error) {
    var u User
    if err := r.db.WithContext(ctx).First(&u, id).Error; err != nil {
        return nil, fmt.Errorf("get user %d: %w", id, err)
    }
    return &u, nil
}

